import axios from 'axios';


const BASE_URL="https://api.themoviedb.org/3";
const Img_URL = "https://image.tmdb.org/t/p/original/";

export const fetchMovie=async(url)=>{
    const {data}= await axios.get(`${BASE_URL}/movie/${url}?api_key=${process.env.REACT_APP_API_KEY}`);
    return data;
};

export const fetchSearch=async(search)=>{
    const response= await axios.get(`${BASE_URL}/${search}/movie?api_key=${process.env.REACT_APP_API_KEY}`);
    return response;
};

export const fetchMovieDetails=async(search)=>{
    const response= await axios.get(`${BASE_URL}/${search}/movie?api_key=${process.env.REACT_APP_API_KEY}`);
    return response;
};
